import torch
from torchvision import models, transforms
from torch.utils.data import DataLoader, Dataset

# Function to download and load a pretrained model from a URL
def load_pretrained_model(url):
    # Load the model architecture
    model = models.resnet18(pretrained=False)
    
    # Download the model weights from the given URL
    state_dict = torch.hub.load_state_dict_from_url(url, map_location=torch.device('cpu'))
    
    # Load the weights into the model
    model.load_state_dict(state_dict)
    
    return model

# Function to fine-tune a model on a custom dataset
def fine_tune_model(model, train_dataset, num_epochs=10):
    # Define loss function and optimizer
    criterion = torch.nn.CrossEntropyLoss()
    optimizer = torch.optim.SGD(model.parameters(), lr=0.001, momentum=0.9)
    
    # Convert the custom dataset to a DataLoader
    dataloader = DataLoader(train_dataset, batch_size=32, shuffle=True)
    
    # Move model to GPU if available
    device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    model.to(device)
    
    # Fine-tune the model
    for epoch in range(num_epochs):
        running_loss = 0.0
        for inputs, labels in dataloader:
            inputs, labels = inputs.to(device), labels.to(device)
            
            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()
            
            running_loss += loss.item()
        
        print(f'Epoch {epoch+1}, Loss: {running_loss/len(dataloader)}')

